+/// Compile JS to raw bytecode format using qjsc -b
+fn compileWithQjscRaw(allocator: std.mem.Allocator, input_file: []const u8, output_path: []const u8) !u8 {
+    const self_exe = try std.fs.selfExePathAlloc(allocator);
