+        std.debug.print("Error: qjsc not found at {s}\n", .{qjsc_path});
+        return 1;
+    };
+
+    const argv = [_][]const u8{
+        qjsc_path,
+        "-b", // Output raw bytecode
+        "-o",
+        output_path,
+        input_file,
+    };
